#nullable enable // autogenerated

using System.Xml;
using MVZ2.IO;

namespace MVZ2.Metas
{
    public class AlmanacVariableOperationPlus : AlmanacVariableOperationUnary
    {
        public AlmanacVariableOperationPlus(AlmanacVariableReference reference) : base(reference)
        {
        }

        public override double Operate(AlmanacVariableContext context, double value)
        {
            return value + GetOperand(context);
        }
        public static AlmanacVariableOperationPlus? FromXmlNode(XmlNode node, string defaultNsp)
        {
            var reference = XMLHelper.GetAlmanacVariableReference(node, defaultNsp);
            if (reference == null)
            {
                Log.LogError($"Cannot load variable reference of {nameof(AlmanacVariableOperationPlus)}.");
                return null;
            }
            return new AlmanacVariableOperationPlus(reference);
        }
    }
}
